import './TransactionForm.css';
function TransactionForm() {
    return (
        <>
        <div className="transactionForm-container">
            <div className="add-transaction">Add Transaction</div>
            <div className="transaction-input-container">
                <input type="number" name='Amount' if='transact-amount'/>
                <input type="text" name="Category" id="transact-category" />
                <input type="text" name="Date" id="transact-date" />
            </div>
        </div>
        </>
    )
};
export default TransactionForm;
